import time, statistics
def work():
    return sum(i*i for i in range(5000))
work()  # warmup
times = []
for _ in range(5):
    t0 = time.perf_counter(); work(); times.append(time.perf_counter()-t0)
print("median_ms", round(statistics.median(times)*1000, 3))
print("n_runs", 5)
print("warmup", True)

