import time
def bench(fn, n=5):
    fn(); ts=[]
    for _ in range(n):
        t0=time.perf_counter(); fn(); ts.append(time.perf_counter()-t0)
    return sorted(ts)[len(ts)//2]
if __name__=='__main__':
    print(bench(lambda: sum(range(1000))))
